func TestGoSemverParity(t *testing.T) {
	p := NewProvider(nil)
	eco, ok := p.Get("Go")
	if !ok {
		t.Skip("Go ecosystem not available")
	}
	if !eco.IsSemver() {
		t.Error("Go ecosystem should report IsSemver()=true")
	}
	for _, v := range []string{"1.21.0", "1.22.3", "0.18.0"} {
		if _, err := eco.Parse(v); err != nil {
			t.Errorf("Go.Parse(%q) unexpected error: %v", v, err)
		}
	}
}

